<template>
	<div
		class="container"
		ref="container"></div>
</template>

<script>
	import * as d3 from 'd3';
	// import data from './assets/flare-2.json'
	import data from './assets/flare-2.simple.json';
	import tree from './d3-hierarchy/tree.js';
	import Tree from '../../utils/data_struct/tree/tree.js';

	// let	t = new Tree(data);

	// console.log('t:', t);
	// t.forEachBB((t)=>{
	// 	console.log(t.data.name);
	// });

	export default {
		mounted(){
			let 
				container = this.$refs.container,
				width = container.clientWidth,
				// height = container.clientHeight,

				root = d3.hierarchy(data),

				padding = 1,
				// Compute the layout.
				dx = 30,
				dy = 160
			// console.log('d3.hierarchy(data):', d3.hierarchy(data));
			// d3.tree().nodeSize([dx, dy])(root);
			tree().nodeSize([dx, dy])(root);

			// console.log('dy:', dy);
			// console.log('d3.tree:', d3.tree);
			// console.log('d3.tree().nodeSize:', d3.tree().nodeSize);
			// console.log('root:', root);
			// console.log('d3.tree().nodeSize([dx, dy])(root):', d3.tree().nodeSize([dx, dy])(root));
			// console.log('d3.linkHorizontal():', d3.linkHorizontal());


			let x0 = Infinity,
					x1 = -x0;

			root.each(d => {
				if (d.x > x1) {
					x1 = d.x;
				}
				if (d.x < x0) {
					x0 = d.x;
				}
			});

			// console.log('root:', root);
			// console.log('data:', data);
			// console.log('data:', JSON.stringify(data));
			let 
					height = x1 - x0 + dx * 2,
					svg = d3.select(container)
						.append('svg')
						// .attr("viewBox", [-dy * padding / 2, x0 - dx, width, height])
						.attr("viewBox", [-100,  -height / 2, width, height])
						.attr("width", '100%')
						.attr("height", '100%')
						// .attr("style", "max-width: 100%; height: auto; height: intrinsic;")
						// .attr("font-family", "sans-serif")

		  svg.append("g")
		      .attr("fill", "none")
		      .attr("stroke", "#555")
		      .attr("stroke-opacity", 0.4)
		      .attr("stroke-width", 1.5)
			    .selectAll("path")
		      .data(root.links())
		      .join("path")
	        .attr("d", d3.linkHorizontal()
	          .x((d)=>{
	          	// console.log('d:', d);
	          	return d.y;
	          })
	          .y((d)=>{
	          	// console.log('d:', d);
	          	return d.x;
	          }));

	    // console.log('d3.linkHorizontal:', d3.linkHorizontal);

			const node = svg.append("g")
				.selectAll("a")
				.data(root.descendants())
				.join("a")
				.attr("transform", d => `translate(${d.y},${d.x})`);

			node.append("circle")
					.attr("fill", d => d.children ? "#555" : "#999")
					.attr("r", 3);

			node.append("text")
				.attr("dy", "0.32em")
				.attr("x", d => d.children ? -6 : 6)
				.attr("text-anchor", d => d.children ? "end" : "start")
				.attr("paint-order", "stroke")
				.attr("stroke", "#fff")
				.attr("stroke-width", 3)
				.attr("font-size", 10)
				.text((d, i) => {
					return d.data.name;
				});

		}
	}
</script>